#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        long long count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i; j < N; j++) {
                int* set1 = (int*)malloc((j - i + 1) * sizeof(int));
                int size1 = 0;
                for (int k = i; k <= j; k++) {
                    int flag = 0;
                    for (int l = 0; l < size1; l++) {
                        if (set1[l] == A[k]) {
                            flag = 1;
                            break;
                        }
                    }
                    if (!flag) {
                        set1[size1] = A[k];
                        size1++;
                    }
                }
                for (int k = j + 1; k < N; k++) {
                    for (int l = k; l < N; l++) {
                        int* set2 = (int*)malloc((l - k + 1) * sizeof(int));
                        int size2 = 0;
                        int flag = 0;
                        for (int m = k; m <= l; m++) {
                            for (int n = 0; n < size1; n++) {
                                if (A[m] == set1[n]) {
                                    flag = 1;
                                    break;
                                }
                            }
                            if (flag) break;
                            int flag2 = 0;
                            for (int n = 0; n < size2; n++) {
                                if (set2[n] == A[m]) {
                                    flag2 = 1;
                                    break;
                                }
                            }
                            if (!flag2) {
                                set2[size2] = A[m];
                                size2++;
                            }
                        }
                        if (!flag) count++;
                        free(set2);
                    }
                }
                free(set1);
            }
        }
        printf("%lld\n", count);
        free(A);
    }
    return 0;
}

